import java.util.*;

public class ArrayListDemo {
 public static void main(String[] args) {
 // Create ArrayList with initial capacity
 ArrayList<String> list = new ArrayList<>(20);

 // Add elements
 list.add("Apple"); // Appends to end
 list.add("Banana");
 list.add(1, "Mango"); // Insert at index 1

 // Remove elements
 list.remove("Banana"); // By object
 list.remove(0); // By index

 // Iterate using different methods
 // Method 1: Enhanced for-loop
 for (String s : list) {
 System.out.println(s);
 }

 // Method 2: Iterator
 Iterator<String> it = list.iterator();
 while (it.hasNext()) {
 String s = it.next();
 if (s.equals("Mango")) {
 it.remove(); // Safe removal
 }
 }

 // Method 3: forEach with lambda
 list.forEach(s -> System.out.println(s));

 // Method 4: ListIterator for bidirectional traversal
 ListIterator<String> lit = list.listIterator();
 while (lit.hasNext()) {
 lit.next();
 }
 while (lit.hasPrevious()) {
 System.out.println(lit.previous());
 }
 }
}

import java.util.*;

class Employee {
 String name;
 int age;
 double salary;

 Employee(String name, int age, double salary) {
 this.name = name;
 this.age = age;
 this.salary = salary;
 }

 @Override
 public String toString() {
 return name + "-" + age + "-$" + salary;
 }
}

public class ComparatorDemo {
 public static void main(String[] args) {
 List<Employee> employees = new ArrayList<>();
 employees.add(new Employee("John", 30, 50000));
 employees.add(new Employee("Alice", 25, 60000));
 employees.add(new Employee("Bob", 30, 45000));

 // Natural order via Comparable (by name if implemented)
 // Using Comparator for custom sorting

 // Sort by age (ascending)
 Collections.sort(employees, (e1, e2) -> e1.age - e2.age);

 // Sort by salary (descending)
 Collections.sort(employees, (e1, e2) -> 
 Double.compare(e2.salary, e1.salary));

 // Sort by age, then by salary (chained)
 Collections.sort(employees, 
 Comparator.comparingInt(Employee::getAge)
 .thenComparingDouble(Employee::getSalary));

 // Using Comparator method reference
 employees.sort(Comparator.comparing(Employee::getName));

 // Reverse order
 employees.sort(Comparator.reverseOrder());
 }
}

import java.util.*;

public class HashMapDemo {
 public static void main(String[] args) {
 Map<String, Integer> map = new HashMap<>();

 // Basic operations
 map.put("One", 1);
 map.put("Two", 2);
 map.putIfAbsent("Three", 3); // Only if key not present

 // Get with default value
 int value = map.getOrDefault("Four", 0);

 // Merge values
 map.merge("One", 10, (old, neu) -> old + neu); // Adds 10 to existing

 // Compute operations
 map.compute("Two", (k, v) -> v == null ? 0 : v * 2);
 map.computeIfAbsent("Five", k -> k.length());

 // Different iteration methods
 // 1. Entry set iteration
 for (Map.Entry<String, Integer> entry : map.entrySet()) {
 System.out.println(entry.getKey() + " = " + entry.getValue());
 }

 // 2. KeySet iteration
 for (String key : map.keySet()) {
 System.out.println(key + ": " + map.get(key));
 }

 // 3. forEach with lambda
 map.forEach((k, v) -> System.out.println(k + "->" + v));

 // 4. Using streams (Java 8+)
 map.entrySet().stream()
 .filter(e -> e.getValue() > 5)
 .forEach(System.out::println);

 // Check operations
 System.out.println(map.containsKey("One"));
 System.out.println(map.containsValue(10));

 // Remove operations
 map.remove("One");
 map.remove("Two", 2); // Only if key-value pair matches
 }
}
